from typing import List
from ..models import USERS, UserOut
from ..auth import get_current_user

router = APIRouter(prefix="/users", tags=["users"])

@router.get("/me", response_model=UserOut)
def read_users_me(current_user: UserOut = Depends(get_current_user)):
    return current_user

@router.get("/", response_model=List[UserOut])
def read_users(current_user: UserOut = Depends(get_current_user)):
    return [UserOut(id=u.id, username=u.username, email=u.email) for u in USERS]

@router.put("/{user_id}", response_model=UserOut)
def update_user(user_id: int, email: str, current_user: UserOut = Depends(get_current_user)):
    for user in USERS:
        if user.id == user_id:
            user.email = email
            return UserOut(id=user.id, username=user.username, email=user.email)
    raise HTTPException(status_code=404, detail="User not found")

@router.delete("/{user_id}")
def delete_user(user_id: int, current_user: UserOut = Depends(get_current_user)):
    for i, user in enumerate(USERS):
        if user.id == user_id:
            del USERS[i]
            return {"deleted": user_id}
    raise HTTPException(status_code=404, detail="User not found")
